/// Validate that a URL's host is in the allowlist and does not resolve to a blocked IP.
fn validate_url(url_str: &str, allowed_hosts: &HashSet<String>) -> Result<Url, String> {
    // Parse the URL
    let url = Url::parse(url_str).map_err(|e| format!("Invalid URL: {}", e))?;

    // Only allow HTTPS
    if url.scheme() != "https" {
        return Err("Only HTTPS URLs are allowed".to_string());
    }

    // Extract host
    let host = url
        .host_str()
        .ok_or_else(|| "URL must have a host".to_string())?;

    // Check against allowlist
    if !allowed_hosts.contains(host) {
        return Err(format!("Host '{}' is not in the allowed hosts list", host));
    }

    // Resolve the hostname and check all resolved IPs
    let port = url.port_or_known_default().unwrap_or(443);
    let addr_str = format!("{}:{}", host, port);

    let resolved_addrs: Vec<std::net::SocketAddr> = addr_str
        .to_socket_addrs()
        .map_err(|e| format!("Failed to resolve host '{}': {}", host, e))?
        .collect();

    if resolved_addrs.is_empty() {
        return Err(format!("Host '{}' did not resolve to any addresses", host));
    }

    for addr in &resolved_addrs {
        if is_blocked_ip(&addr.ip()) {
            return Err(format!(
                "Host '{}' resolves to blocked IP address: {}",
                host,
                addr.ip()
            ));
        }
    }

    Ok(url)
}

