fn build_allowed_hosts() -> HashSet<String> {
    // Configure your allowed partner API hosts here.
    // In production, load from configuration file or environment variables.
    let mut hosts = HashSet::new();

    // Read from environment variable ALLOWED_HOSTS (comma-separated)
    if let Ok(env_hosts) = std::env::var("ALLOWED_HOSTS") {
        for host in env_hosts.split(',') {
            let trimmed = host.trim().to_lowercase();
            if !trimmed.is_empty() {
                hosts.insert(trimmed);
            }
        }
    }

    // Default allowed hosts if none configured (for demonstration)
    if hosts.is_empty() {
        hosts.insert("api.partner-one.com".to_string());
        hosts.insert("api.partner-two.com".to_string());
        hosts.insert("webhooks.partner-three.com".to_string());
    }

    hosts
}

